head.script:
scwin.initData = {
	"title" : {
		"H" : "한강유역본부",
		"G" : "금강유역본부",
		"Y" : "영섬강유역본부",
		"N" : "낙동강유역본부"
	},
	"basinCode" : {
		"ALL" : "ALL",
		"H" : "01",
		"G" : "02",
		"Y" : "03",
		"N" : "04"
	},
	"chart" : {
		"prdctnUnit" : 10,
		"prdctnIntervalCount" : 3,
		"cnstnUnit" : 10,
		"cnstnIntervalCount" : 3
	},
	"prdctnDisplayData" : {
		"Lgwtpw" : "대수력",
		"Smlhp" : "소수력",
		"GnrlSmlhp" : "소수력",
		"BoSmlhp" : "보소수력",
		"Tdpw" : "조력",
		"Wtht" : "수열",
		"Snpw" : "태양광",
		"Wdpw" : "풍력"
	},
	"setcscDivCd" : {
		"대수력" : 10,
		"소수력" : 21,
		"보소수력" : 22,
		"조력" : 30,
		"수열" : "",
		"태양광" : 40,
		"풍력" : 50
	},
	"cnstnDisplayData" : {
		"Itkpl" : "취수시설",
		"Prnplc" : "가압시설",
		"Fltplt" : "정수시설",
		"Buld" : "건물",
		"Trnsp" : "수송",
		"Dam" : "댐시설",
		"Etc" : "기타"
	},
	"observeEvent" : false,
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	var basin = $p.getParameter("param").basin;
	var scrinId = "";
	switch (basin) {
		case "H":
			scrinId = "ECSEC5100000";
			break;
		case "G":
			scrinId = "ECSEC5200000";
			break;
		case "N":
			scrinId = "ECSEC5300000";
			break;
		case "Y":
			scrinId = "ECSEC5400000";
			break;
		default:
			break;
	}
	if (!scrinId) {
		return;
	}
	comLib.initForm($p, scrinId);

	// 지도 정보 조회
	scwin.searchBasinMapInfo();

	// 사이클 데이터 조회
	scwin.searchDatas();

	// 유역 운영현황 초기 데이터 조회
	scwin.searchBasinDeptPCSttusData("");

	// 전주기 현황 타이틀 클릭시 이동
	scwin.setCycleLabelClickEvent();

	spnBasinTitle.setLabel(`(${scwin.initData.title[basin]})`);
	// 초기 그리드 유역 이름 설정_240305
	spnBrffcNm.setLabel(`${scwin.initData.title[basin]}`);

	// ecsLib.setChartResizeObserver(this);
};

/**
 * 데이터들을 조회한다.
 */
scwin.searchDatas = function() {
	// 탄소중립율 데이터 조회 (2024.02.06 김동현 차장님 요청으로 삭제)
	// scwin.searchCbnNtrltData();
	// 전주기 현황 계획 데이터 조회
	scwin.searchRecyclePData();
	// 전주기 현황 건설 데이터 조회
	scwin.searchRecycleBData();
	// 전주기 현황 관리 데이터 조회
	scwin.searchRecycleMData();
	// 전주기 현황 폐기 데이터 조회
	scwin.searchRecycleEData();

	// 전주기 현황 정산-생산, 소비 데이터 조회
	scwin.searchCyclePC();
	// 전주기 현황 정산-발전수익 데이터 조회
	scwin.searchElyrsErnData();
	// 전주기 현황 정산-기타수익 데이터 조회
	scwin.searchEtcErnData();
	// 전주기 현황 정산-소비정산 데이터 조회
	scwin.searchCnstnExcclcData();
};

//============================================================================================
// 차트
//============================================================================================

/**
 * 생산, 생산정산 차트 X축 라벨 핸들러
 * @param {
 	id : ID,
 	value : 값
 }
 * @return 라벨 내용
 */
scwin.prdctnCategoryLabelHandler = function(id, value) {
	return "        " + value;
};

/**
 * 생산, 생산정산 차트 Y축 라벨 핸들러
 * @param {
 	id : ID,
 	value : 값
 }
 * @return 라벨 내용
 */
scwin.prdctnLinearLabelHandler = function(id, value) {
	return "  " + ecsLib.numCommaFrmt(value);
};

/**
 * 전력 생산량/전력 소비량 및 정산금액 itemClick 핸들러
 * @param {
 	seriesID : ID,
 	displayText : tooltip display data,
 	index : 인덱스,
 	data : 데이터 맵,
 	values : 값
 }
 * @return 시리즈 색상
 */
scwin.chartItemClickHandler = function(seriesId, displayText, index, data, values) {
	var targetParentMenuId = "";
	var targetMenuId = "";
	var param = {};
	param.basinCd = scwin.initData.basinCode[$p.getParameter("param").basin];

	if (displayText.includes("생산량")) {
		targetParentMenuId = "ECSPN000000";
		targetMenuId = "ECSPN200000";
		param.setcscDivCd = scwin.initData.setcscDivCd[data.name];

		param.year = utilLib.getCurrentDate("yyyy");
	} else if (displayText.includes("수익금")) {
		targetParentMenuId = "ECSCL000000";
		targetMenuId = "ECSCL110000";
		param.setcscDivCd = scwin.initData.setcscDivCd[data.name] == 21 ? 20 : scwin.initData.setcscDivCd[data.name];
		param.year = utilLib.getCurrentDate("yyyy");
		param.type = "Y";
	} else if (displayText.includes("소비량") || displayText.includes("정산금")) {
		targetParentMenuId = "ECSCN000000";
		targetMenuId = "ECSCN100000";
		param.year = utilLib.getCurrentDate("yyyy");
		param.type = "Y";
	} else {
		return;
	}

	ecsLib.chartMenuClickEvent(
		targetParentMenuId,
		targetMenuId,
		param
	);
};

/**
* 생산, 생산정산 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerPrdctn = function(id) {
	var prdctnChartData = dltPrdctnList.getAllJSON();
	var tempObj = {};
	prdctnChartData.filter(obj => obj.cmmnCdNm.endsWith("소수력")).forEach(obj => {
		Object.keys(obj).forEach(key => {
			if (!tempObj[key]) {
				tempObj[key] = obj[key];
			} else if (tempObj[key] && key.endsWith("Vu")) {
				tempObj[key] = Number(tempObj[key]) + Number(obj[key]);
			}
		});
	});
	/*
	if (Object.keys(tempObj).length) {
		tempObj.cmmnCdNm = "소수력";
		tempObj.cmmnCdNmEn = Object.keys(scwin.initData.prdctnDisplayData).find(key => scwin.initData.prdctnDisplayData[key] == "소수력");
		prdctnChartData = prdctnChartData.filter(obj => !obj.cmmnCdNm.endsWith("소수력"));
		prdctnChartData.push(tempObj);
	}
	*/

	var chartList = [];
	Object.keys(scwin.initData.prdctnDisplayData).forEach(source => {
		var data = prdctnChartData.find(obj => obj.cmmnCdNmEn.toLowerCase() == source.toLowerCase());
		if (data) {
			chartList.push({
				"name" : data.cmmnCdNm,
				"prdctn" : data.prdctnVu,
				"prdctnExcclc" : data.prdctnExcclcVu
			});
		}
	});

	var maxPData = chartList.reduce((max, obj) => Math.max(max, obj.prdctn), 0)
	var maxCpData = chartList.reduce((max, obj) => Math.max(max, obj.prdctnExcclc), 0)
	var minPData = chartList.reduce((min, obj) => Math.min(min, obj.prdctn), 0)
	var minCpData = chartList.reduce((min, obj) => Math.min(min, obj.prdctnExcclc), 0)
	var pInterval = Math.ceil((maxPData / scwin.initData.chart.prdctnIntervalCount) / scwin.initData.chart.prdctnUnit) * scwin.initData.chart.prdctnUnit;
	var cpInterval = Math.ceil((maxCpData / scwin.initData.chart.prdctnIntervalCount) / 10) * 10;
	var sumPData = new Intl.NumberFormat("ko-KR").format(chartList.reduce((sum, obj) => sum + Number(obj.prdctn), 0));
	var sumCpData = new Intl.NumberFormat("ko-KR").format(chartList.reduce((sum, obj) => sum + Number(obj.prdctnExcclc), 0));
	var titleText = ecsLib.dsplFrmt(sumPData, 2)
		+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;MWh&lt;/span&gt;'
		+ '&amp;ensp;&lt;span style=&quot;color:#AFAFAF;font-weight:normal;&quot;&gt;|&lt;/span&gt;&amp;ensp;'
		+ '&lt;span style=&quot;color:#219D9D;&quot;&gt;'
		+ ecsLib.dsplFrmt(sumCpData, 2)
		+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;백만&lt;/span&gt;'
		+ '&lt;/span&gt;';
	var pMinimum = "";
	if (minPData < 0) {
		pMinimum = `minimum="${minPData}"`;
	}
	var cpMinimum = "";
	if (minCpData < 0) {
		cpMinimum = `minimum="${minCpData}"`;
	}

	var layoutStr = '<rMateChart backgroundColor="" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="' + titleText + '" textAlign="right" fontSize="0.87rem" fontWeight="bold" color="#83DCCE"'
		+ '			borderStyle="solid" borderColor="#83DCCE" borderTop="0" borderRight="0" borderBottom="1" borderLeft="0" marginTop="2%" />'
		+ '		<Legend position="center" vAlign="left" hAlign="top" verticalGap="2" border="0" background="transparent" marginTop="-4%" />'
		+ '	</Options>'
		+ '	<Column3DChart showDataTips="true" columnWidthRatio="0.75" type="clustered" maxColumnWidth="25" dataTipDisplayMode="axis" itemClickJsFunction="' + $p.id + 'scwin.chartItemClickHandler">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="name" labelJsFunction="' + $p.id + 'scwin.prdctnCategoryLabelHandler" />'
		+ '		</horizontalAxis>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis3DRenderer axis="{hAxis}" visible="true" textAlign="right" canDropLabels="false" />'
		+ '		</horizontalAxisRenderers>'
		+ '		<verticalAxis>'
		+ '		</verticalAxis>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis3DRenderer axis="{vAxisL}" visible="true" placement="left" verticalAxisTitleAlignment="top" titleGap="0" canDropLabels="false" showLine="false" />'
		+ '			<Axis3DRenderer axis="{vAxisR}" visible="true" placement="right" verticalAxisTitleAlignment="top" titleGap="0" canDropLabels="false" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '		<series>'
		+ '			<Column3DSeries color="#222222" font-weight="bold" yField="prdctn" displayName="전력 생산량" halfWidthOffset="3">'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxisL" interval="' + pInterval + '" ' + pMinimum + ' labelJsFunction="' + $p.id + 'scwin.prdctnLinearLabelHandler" title="MWh" />'
		+ '				</verticalAxis>'
		+ '				<fill>'
		+ '					<SolidColor color="#83DCCE" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column3DSeries>'
		+ '			<Column3DSeries color="#222222" font-weight="bold" yField="prdctnExcclc" displayName="발전 수익금" halfWidthOffset="3">'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxisR" interval="' + cpInterval + '" ' + cpMinimum + ' labelJsFunction="' + $p.id + 'scwin.prdctnLinearLabelHandler" title="백만" />'
		+ '				</verticalAxis>'
		+ '				<fill>'
		+ '					<SolidColor color="#219D9D" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column3DSeries>'
		+ '		</series>'
		+ '	</Column3DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

// 지도 정보 조회
scwin.searchBasinMapInfo = function() {
	var basin = $p.getParameter("param").basin;
	var selector = "#" + $p.getFrameId() + " .main-detail-con-box .main-detail-map .main-detail-box-con .detail-map-basin-" + basin.toLowerCase();
	var basinEmt = document.querySelector(selector);
	basinEmt.classList.remove("hide");

	var queryString = `?ecsBasinDivCd=${basin.toUpperCase()}`;

	var option = {
		action : "ec/main/retrieve-basin-map-info.do"
			+ queryString,
		method : "get",
		resData : dltBasinMapInfo,
		success : "scwin.searchBasinMapInfoCallBack",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

// 지도 정보 조회 콜백
scwin.searchBasinMapInfoCallBack = function() {
	// 유역별 지도 클릭 이벤트
	var basin = $p.getParameter("param").basin;
	var selector = "#" + $p.getFrameId() + " .main-detail-con-box .main-detail-map .main-detail-box-con .detail-map-basin-" + basin.toLowerCase();
	var basinEmt = document.querySelector(selector);
	ecsLib.createDetailMapBasinInfo($p.getComponentById(basinEmt.id), basin, dltBasinMapInfo.getAllJSON(), scwin.setBasinMapLabelClickEvent);
};

/**
 * 전력에너지 전주기 현황 생산/소비 데이터를 조회한다.
 */
scwin.searchCyclePC = function() {
	var strtDt = utilLib.getCurrentDate("yyyy") - 1;
	var endDt = utilLib.getCurrentDate("yyyy");
	var nowInqireDe = utilLib.calcToday(0, 0, -1);
	var basinCd = scwin.initData.basinCode[$p.getParameter("param").basin] || "ALL";

	var queryString = `?strtDt=${strtDt}`;
	queryString += `&endDt=${endDt}`;
	queryString += `&inqireDe=${nowInqireDe}`;
	queryString += `&ecsBasinDivCd=${basinCd}`;

	var option = {
		action : "ec/main/retrieve-cycle-pc.do"
			+ queryString,
		method : "get",
		resData : dltPCData,
		success : "scwin.searchCyclePCCallBack",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 생산/소비 데이터 조회 콜백
 */
scwin.searchCyclePCCallBack = function(res) {
	// 전주기 현황 생산 데이터 설정
	scwin.setRecyclePrdctnData();
	// 전주기 현황 소비 데이터 설정
	scwin.setRecycleCnstnData();
};

/**
* 소비, 소비정산 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerCnstn = function(id) {
	var cnstnChartData = dltCnstnList.getAllJSON();
	var chartList = [];
	var elcpwstnClsNm = {
		"itkpl" : "취수장",
		"prnplc" : "가압장",
		"fltplt" : "정수장",
		"buld" : "건물",
		"trnsp" : "수송",
		"dam" : "댐시설",
		"etc" : "기타"
	}

	Object.keys(scwin.initData.cnstnDisplayData).forEach(source => {
		var data = cnstnChartData.find(obj => obj.cmmnCdNm.toLowerCase() == source.toLowerCase());
		if (data) {
			chartList.push({
				"name" : elcpwstnClsNm[data.cmmnCdNm],
				"cnstn" : data.cnstnVu,
				"cnstnExcclc" : data.cnstnExcclcVu
			});
		}
	});

	var maxCData = chartList.reduce((max, obj) => Math.max(max, obj.cnstn), 0);
	var maxCcData = chartList.reduce((max, obj) => Math.max(max, obj.cnstnExcclc), 0);
	var minCData = chartList.reduce((min, obj) => Math.min(min, obj.cnstn), 0);
	var minCcData = chartList.reduce((min, obj) => Math.min(min, obj.cnstnExcclc), 0);
	var cInterval = Math.ceil((maxCData / scwin.initData.chart.cnstnIntervalCount) / scwin.initData.chart.cnstnUnit) * scwin.initData.chart.cnstnUnit;
	var ccInterval = Math.ceil((maxCcData / scwin.initData.chart.cnstnIntervalCount) / 10) * 10;
	var sumCData = new Intl.NumberFormat("ko-KR").format(chartList.reduce((sum, obj) => sum + Number(obj.cnstn), 0));
	var sumCcData = new Intl.NumberFormat("ko-KR").format(chartList.reduce((sum, obj) => sum + Number(obj.cnstnExcclc), 0));
	var titleText = ecsLib.dsplFrmt(sumCData, 2)
		+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;MWh&lt;/span&gt;'
		+ '&amp;ensp;&lt;span style=&quot;color:#AFAFAF;font-weight:normal;&quot;&gt;|&lt;/span&gt;&amp;ensp;'
		+ '&lt;span style=&quot;color:#C5385A;&quot;&gt;'
		+ ecsLib.dsplFrmt(sumCcData, 2)
		+ ' &lt;span style=&quot;font-size:0.5em;&quot;&gt;백만&lt;/span&gt;'
		+ '&lt;/span&gt;';
	var cMinimum = "";
	if (minCData < 0) {
		cMinimum = `minimum="${minCData}"`;
	}
	var ccMinimum = "";
	if (minCcData < 0) {
		ccMinimum = `minimum="${minCcData}"`;
	}

	var layoutStr = '<rMateChart backgroundColor="" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="' + titleText + '" textAlign="right" fontSize="0.87rem" fontWeight="bold" color="#FD9EA6"'
		+ '			borderStyle="solid" borderColor="#FD9EA6" borderTop="0" borderRight="0" borderBottom="1" borderLeft="0" marginTop="2%" />'
		+ '		<Legend position="center" vAlign="left" hAlign="top" verticalGap="2" border="0" background="transparent" marginTop="-4%" />'
		+ '	</Options>'
		+ '	<Column3DChart showDataTips="true" columnWidthRatio="0.65" type="clustered" maxColumnWidth="25" dataTipDisplayMode="axis" itemClickJsFunction="' + $p.id + 'scwin.chartItemClickHandler">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="name" />'
		+ '		</horizontalAxis>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis3DRenderer axis="{hAxis}" visible="true" textAlign="right" canDropLabels="false" />'
		+ '		</horizontalAxisRenderers>'
		+ '		<verticalAxis>'
		+ '		</verticalAxis>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis3DRenderer axis="{vAxisL}" visible="true" placement="left" verticalAxisTitleAlignment="top" titleGap="0" canDropLabels="false" showLine="false" />'
		+ '			<Axis3DRenderer axis="{vAxisR}" visible="true" placement="right" verticalAxisTitleAlignment="top" titleGap="0" canDropLabels="false" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '		<series>'
		+ '			<Column3DSeries color="#222222" font-weight="bold" yField="cnstn" displayName="전력 소비량" halfWidthOffset="3">'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxisL" interval="' + cInterval + '" ' + cMinimum + ' labelJsFunction="' + $p.id + 'scwin.prdctnLinearLabelHandler" title="MWh" />'
		+ '				</verticalAxis>'
		+ '				<fill>'
		+ '					<SolidColor color="#FD9EA6" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column3DSeries>'
		+ '			<Column3DSeries color="#222222" font-weight="bold" yField="cnstnExcclc" displayName="소비 정산금" halfWidthOffset="3">'
		+ '				<verticalAxis>'
		+ '					<LinearAxis id="vAxisR" interval="' + ccInterval + '" ' + ccMinimum + ' labelJsFunction="' + $p.id + 'scwin.prdctnLinearLabelHandler" title="백만" />'
		+ '				</verticalAxis>'
		+ '				<fill>'
		+ '					<SolidColor color="#C5385A" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column3DSeries>'
		+ '		</series>'
		+ '	</Column3DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

//============================================================================================
// 전주기 현황
//============================================================================================
/**
 * 전주기 현황 계획 데이터를 조회한다.
 */
scwin.searchRecyclePData = function() {
	var strtDt = utilLib.getCurrentDate("yyyy");
	var endDt = utilLib.getCurrentDate("yyyy");
