/**
 * 유역별 지도 라벨 클릭 이벤트
 */
scwin.setBasinMapLabelClickEvent = function() {
	var basinMapLabel = document.querySelector(`#${$p.getFrameId()} #marker${$p.getParameter("param").basin || "H"}`).childNodes;

	// 초기 유역본부 선택_240305
	var basinMapMarkerheadOffice = document.querySelector(`#${$p.getFrameId()} .detail-map-marker-${($p.getParameter("param").basin || "H").toLowerCase()} .main-detail-head_office`);

	basinMapMarkerheadOffice.children[0].classList.add("main-detail-basin-map-circle");
	basinMapMarkerheadOffice.children[1].classList.add("main-detail-basin-map-label");

	for (var idx = 0; idx < basinMapLabel.length; idx++) {
		// 위탁사업장일 때
		if (basinMapLabel[idx].classList.contains("main-detail-csmt_bplc")) {
			continue;
		}
		// 마우스 포인터 설정
		basinMapLabel[idx].classList.add("cursor-pointer");

		// 유역별 지도 라벨 클릭에 따른 class 추가,삭제 이벤트
		basinMapLabel[idx].addEventListener("click", function(e) {
			if (this.style.opacity) {
				return;
			}
			var basinMapLabel = document.getElementById(`marker${$p.getParameter("param").basin}`).childNodes;
			// 초기 유역본부 선택 해제_240305
			var basinMapMarkerheadOffice = document.querySelector(`#${$p.getFrameId()} .detail-map-marker-${($p.getParameter("param").basin || "H").toLowerCase()} .main-detail-head_office`);

			basinMapMarkerheadOffice.children[0].classList.remove("main-detail-basin-map-circle");
			basinMapMarkerheadOffice.children[1].classList.remove("main-detail-basin-map-label");

			for (var idx1 = 0; idx1 < basinMapLabel.length; idx1++) {
				basinMapLabel[idx1].children[0].classList.remove("main-detail-basin-map-circle");
				basinMapLabel[idx1].children[1].classList.remove("main-detail-basin-map-label");

				if (basinMapLabel[idx1].childElementCount > 2) {
					basinMapLabel[idx1].children[0].classList.remove("main-detail-basin-map-label");
					basinMapLabel[idx1].children[1].classList.remove("main-detail-basin-map-square");
					basinMapLabel[idx1].children[2].classList.remove("main-detail-basin-map-label");
				}
			}

			if (this.childElementCount > 2) {
				this.children[0].classList.add("main-detail-basin-map-label");
				this.children[1].classList.add("main-detail-basin-map-square");
				this.children[2].classList.add("main-detail-basin-map-label");
			} else {
				this.children[0].classList.add("main-detail-basin-map-circle");
				this.children[1].classList.add("main-detail-basin-map-label");
			}

			var brffcLabel = this.textContent;
			// 그리드 유역 이름 설정
			spnBrffcNm.setLabel(brffcLabel);
			// 조건별 그리드 유역 이름 설정_231113
			if (brffcLabel == "한강유역본부, 경기서남권지사, 수도권지역협력단") {
				spnBrffcNm.setLabel("한강유역");
			} else if (brffcLabel == "금강유역본부, 전북지역협력단") {
				spnBrffcNm.setLabel("금강유역");
			} else if (brffcLabel == "낙동강유역본부, 경북지역협력단") {
				spnBrffcNm.setLabel("낙동강유역");
			} else if (brffcLabel == "영섬유역본부, 전남지역협력단") {
				spnBrffcNm.setLabel("영섬유역");
			} else if (brffcLabel == "본사") {
				spnBrffcNm.setLabel("K-water 전체");
			}

			// 사이클 데이터 조회
			scwin.searchDatas();
			// 부서 운영현황 생산, 소비 데이터 조회
			scwin.searchBasinDeptPCSttusData(this.id);
		});
	}

	var basinMapLegendMarkerGroup = document.querySelectorAll(`#${$p.getFrameId()} .detail-map-legend-marker-group-${($p.getParameter("param").basin || "H").toLowerCase()} .detail-map-legend-marker`);
	for (legendMarker of basinMapLegendMarkerGroup) {
		legendMarker.classList.add("cursor-pointer");

		legendMarker.addEventListener("click", function(e) {
			var isSameMarker = false;
			if (this.querySelector("text").getAttribute("font-size") == "11.5") {
				isSameMarker = true;
			}
			if (isSameMarker) {
				var markerGroupFnc = function(emt) {
					var emtText = emt.querySelector("text");
					if (!emtText) {
						return;
					}
					emtText.style.fontWeight = "";
					emtText.style.fill = "";
					emtText.setAttribute("font-size", "10.5");
				};
			} else {
				var markerGroupFnc = function(emt) {
					var emtText = emt.querySelector("text");
					if (!emtText) {
						return;
					}
					var targetEmt = e.target;
					while(targetEmt.tagName.toLowerCase() != "g") {
						targetEmt = targetEmt.parentElement;
						if (targetEmt.tagName.toLowerCase() == "body") {
							break;
						}
					}
					if (emt != targetEmt) {
						emtText.style.fontWeight = "";
						emtText.style.fill = "";
						emtText.setAttribute("font-size", "10.5");
					} else {
						emtText.style.fontWeight = "bold";
						emtText.style.fill = "blue";
						emtText.setAttribute("font-size", "11.5");
					}
				};
			}
			basinMapLegendMarkerGroup.forEach(markerGroupFnc);

			var classNm = [...this.classList].find(item => item.startsWith("detail-map-legend-marker-"));
			var markers = document.querySelectorAll(`#${$p.getFrameId()} .detail-map-marker-${($p.getParameter("param").basin || "H").toLowerCase()} > g`);
			for (marker of markers) {
				if (isSameMarker) {
					marker.style.opacity = "";
					if (!marker.classList.contains("main-detail-csmt_bplc")) {
						marker.classList.add("cursor-pointer");
					}
				} else {
					if (marker.classList.contains(`main-detail-${classNm.split("-").slice(-1)[0]}`)) {
						marker.style.opacity = "";
						if (!marker.classList.contains("main-detail-csmt_bplc")) {
							marker.classList.add("cursor-pointer");
						}
					} else {
						marker.style.transition = "250ms all ease";
						marker.style.opacity = "0.05";
						marker.classList.remove("cursor-pointer");
					}
				}
			}
		});
	}
};

/**
 * 부서 운영현황 생산/소비 그리드, 차트 데이터 조회
 */
scwin.searchBasinDeptPCSttusData = function(emtId) {
	var strtDt = utilLib.getCurrentDate("yyyy");
	var endDt = utilLib.getCurrentDate("yyyy");
	var basinCd = scwin.initData.basinCode[$p.getParameter("param").basin] || "ALL";

	var dept = emtId.split("_").slice(-1)[0];

	var markerNms = Object.assign({}, scwin.initData.basinCode);
	delete markerNms["ALL"];
	if (!dept || !Number(dept)) {
		if (dept.toUpperCase() == "ALL") {
			basinCd = "ALL";
			dept = "";
		} else if (!dept || Object.keys(markerNms).includes(dept)) {
			dept = "";
		}
	}

	var queryString = `?strtDt=${strtDt}`;
	queryString += `&endDt=${endDt}`;
	queryString += `&ecsBasinDivCd=${basinCd}`;
	queryString += `&ecsChrgDeptId=${dept}`;

	var option = {
		action : "ec/main/retrieve-basin-dept-prdctn-sttus.do"
			+ queryString,
		method : "get",
		resData : dltPrdctnList,
		success : "scwin.searchBasinDeptPrdctnSttusCallBack",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);

	var option = {
		action : "ec/main/retrieve-basin-dept-cnstn-sttus.do"
			+ queryString,
		method : "get",
		resData : dltCnstnList,
		success : "scwin.searchBasinDeptCnstnSttusCallBack",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.searchBasinDeptPrdctnSttusCallBack = function() {
	var dltPrdctn = dltPrdctnList.getAllJSON();
	spnPrdctnNum.setLabel(dltPrdctn.length);
	// 차트 데이터 넣기
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerPrdctn";
	rMateChartH5.create($p.id + "chartPrdctn", grpMainChartPrdctn.getID(), chartVars, "98%", "99%");
};

scwin.searchBasinDeptCnstnSttusCallBack = function() {
	var dltCnstn = dltCnstnList.getAllJSON();
	spnCnstnNum.setLabel(dltCnstn.length);
	// 차트 데이터 넣기
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerCnstn";
	rMateChartH5.create($p.id + "chartCnstn", grpMainChartCnstn.getID(), chartVars, "98%", "99%");
};
